        &QueryString;

declare @name nvarchar(4000)
select @name = rtrim(isnull(case when @@language = 'V' then ten_vt else ten_vt2 end, '')) from dmvt where ma_vt = @ma_vt
select 'this._itemName = ''' + replace(replace(isnull(@name, ''), '\', '\\'), '''', '\''') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;





      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmvt b on a.ma_vt = b.ma_vt'
select @queryWhereClause = 'a.ma_vt = ''' +  replace(@ma_vt, '''', '''''') + '''' + ' and a.nxt = ''2'''
select @queryWhereClause = @queryWhereClause + ' and a.gia_nt2 = ' + rtrim(@gia_nt2)
select @queryWhereClause = @queryWhereClause + ' and a.gia2 = ' + rtrim(@gia2)

if @so_ct1 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct >= ''' + dbo.ff_PadL(replace(rtrim(@so_ct1), '''', ''''''), @maxLength) + ''''
if @so_ct2 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct <= ''' + dbo.ff_PadL(replace(rtrim(@so_ct2), '''', ''''''), @maxLength) + ''''
if @ma_kho <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kho like ''' + replace(rtrim(@ma_kho), '''', '''''') + '%'''
if @ma_nvbh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nvbh like ''' + replace(rtrim(@ma_nvbh), '''', '''''') + '%'''
if @tk_vt <> '' select @queryWhereClause = @queryWhereClause + ' and a.tk_vt like ''' + replace(rtrim(@tk_vt), '''', '''''') + '%'''
if @tk_dt <> '' select @queryWhereClause = @queryWhereClause + ' and a.tk_dt like ''' + replace(rtrim(@tk_dt), '''', '''''') + '%'''
if @ma_nx <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nx like ''' + replace(rtrim(@ma_nx), '''', '''''') + '%'''
if @ma_vv <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_vv like ''' + replace(rtrim(@ma_vv), '''', '''''') + '%'''
if @ma_bp <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_bp like ''' + replace(rtrim(@ma_bp), '''', '''''') + '%'''
if @ma_hd <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_hd like ''' + replace(rtrim(@ma_hd), '''', '''''') + '%'''
if @tinh_ps = '0' select @queryWhereClause = @queryWhereClause + ' and a.ct_dc <> 1'
if @ma_gd <> '' select @queryWhereClause = @queryWhereClause + ' and ma_gd in (''' + replace(replace(replace(@ma_gd, ' ', ''), '''', ''''''), ',', ''',''') + ''')'
if @ma_kh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'''
exec rs_GetTransactionKey @ds_ma_ct, @transactionList, 1, 'rptSalesSummaryByPrice', '@@sysDatabaseName', 'a.',	@queryWhereClause output

