      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._itemName, true], ['%d1', formatDateView(a[3]), true], ['%d2', formatDateView(a[4]), true]]];
  var x = a[16];
  g._hiddenFields = [{Fields: 'gia_nt2, tien_nt2, thue_nt, ck_nt, pt_nt, gia_nt, tien_nt_x, lai_nt, ma_nt, ty_gia', Value: (x == '10')}];
}
